mapper.select:
SELECT d.drug_id, d.drug_name, d.approval_no, d.specification, d.manufacturer, d.drug_category, db.batch_no, db.current_stock, d.stock_warning, db.expiry_date, db.expiry_warning_days, d.create_time, CASE WHEN db.current_stock < d.stock_warning THEN 1 ELSE 0 END AS stock_warning_flag, CASE WHEN DATEDIFF(db.expiry_date, CURDATE()) < db.expiry_warning_days THEN 1 ELSE 0 END AS expiry_warning_flag FROM drug d LEFT JOIN drug_batch db ON d.drug_id = db.drug_id WHERE 1=1
AND d.drug_name LIKE CONCAT('%', #{drugName}, '%')
AND d.manufacturer LIKE CONCAT('%', #{manufacturer}, '%')
AND d.drug_category = #{drugCategory}
LIMIT #{pageSize} OFFSET #{offset}
